+    pub async fn handle_invoke(&mut self, params: serde_json::Value) -> FcpResult<serde_json::Value> {
+        let operation = params
+            .get("operation")
+            .and_then(|v| v.as_str())
+            .ok_or_else(|| FcpError::InvalidRequest {
+                code: 1001,
+                message: "Missing 'operation' field".into(),
+            })?;
+
+        let input = params.get("input").cloned().unwrap_or(json!({}));
+        let client = self.client.as_ref().ok_or(FcpError::NotConfigured)?;
+
+        self.base.record_request(true);
+
+        match operation {
+            "sheets.get_spreadsheet" => {
+                let spreadsheet_id = input
+                    .get("spreadsheet_id")
+                    .and_then(|v| v.as_str())
+                    .ok_or_else(|| FcpError::InvalidRequest {
+                        code: 1001,
+                        message: "Missing 'spreadsheet_id'".into(),
+                    })?;
+                let ss = client.get_spreadsheet(spreadsheet_id).await.map_err(|e| {
+                    self.base.record_request(false);
+                    e.to_fcp_error()
+                })?;
+                Ok(json!({ "spreadsheet": ss }))
+            }
+            "sheets.get_values" => {
+                let spreadsheet_id = require_str(&input, "spreadsheet_id")?;
+                let range = require_str(&input, "range")?;
+                let vr = client.get_values(spreadsheet_id, range).await.map_err(|e| {
+                    self.base.record_request(false);
+                    e.to_fcp_error()
+                })?;
+                Ok(json!({ "range": vr.range, "values": vr.values }))
+            }
+            "sheets.update_values" => {
+                let spreadsheet_id = require_str(&input, "spreadsheet_id")?;
+                let range = require_str(&input, "range")?;
+                let values = input
+                    .get("values")
+                    .and_then(|v| serde_json::from_value::<Vec<Vec<serde_json::Value>>>(v.clone()).ok())
+                    .ok_or_else(|| FcpError::InvalidRequest {
+                        code: 1001,
+                        message: "Missing or invalid 'values' (must be 2D array)".into(),
+                    })?;
+                let ur = client
+                    .update_values(spreadsheet_id, range, values)
+                    .await
+                    .map_err(|e| {
+                        self.base.record_request(false);
+                        e.to_fcp_error()
+                    })?;
+                Ok(json!({
+                    "updated_range": ur.updated_range,
+                    "updated_cells": ur.updated_cells,
+                    "updated_rows": ur.updated_rows,
+                }))
+            }
+            "sheets.append_values" => {
+                let spreadsheet_id = require_str(&input, "spreadsheet_id")?;
+                let range = require_str(&input, "range")?;
+                let values = input
+                    .get("values")
+                    .and_then(|v| serde_json::from_value::<Vec<Vec<serde_json::Value>>>(v.clone()).ok())
+                    .ok_or_else(|| FcpError::InvalidRequest {
+                        code: 1001,
+                        message: "Missing or invalid 'values'".into(),
+                    })?;
+                let ar = client
+                    .append_values(spreadsheet_id, range, values)
+                    .await
+                    .map_err(|e| {
+                        self.base.record_request(false);
+                        e.to_fcp_error()
+                    })?;
+                Ok(json!({
+                    "table_range": ar.table_range,
+                    "updates": ar.updates,
+                }))
+            }
+            "sheets.clear_values" => {
+                let spreadsheet_id = require_str(&input, "spreadsheet_id")?;
+                let range = require_str(&input, "range")?;
+                let result = client
+                    .clear_values(spreadsheet_id, range)
+                    .await
+                    .map_err(|e| {
+                        self.base.record_request(false);
+                        e.to_fcp_error()
+                    })?;
+                Ok(result)
+            }
+            _ => Err(FcpError::InvalidRequest {
+                code: 1002,
+                message: format!("Unknown operation: {operation}"),
+            }),
+        }
+    }
+
+    pub async fn handle_simulate(&self, params: serde_json::Value) -> FcpResult<serde_json::Value> {
+        let operation = params
+            .get("operation")
+            .and_then(|v| v.as_str())
+            .unwrap_or("unknown");
